import{_ as l,o as a,c as d,a2 as i}from"./chunks/framework.BflysNKA.js";const n=JSON.parse('{"title":"Claude Code Hub","description":"","frontmatter":{},"headers":[],"relativePath":"tools/claude-code-hub.md","filePath":"tools/claude-code-hub.md","lastUpdated":1778577020000}'),o={name:"tools/claude-code-hub.md"};function u(t,e,r,c,h,s){return a(),d("div",null,[...e[0]||(e[0]=[i('<h1 id="claude-code-hub" tabindex="-1">Claude Code Hub <a class="header-anchor" href="#claude-code-hub" aria-label="Permalink to &quot;Claude Code Hub&quot;">​</a></h1><p>Claude Code Hub 适合把 Claude Code 的配置集中起来管理，尤其适合多设备或多人协作环境。</p><p>它更像一个“面向 Claude Code 的统一配置入口”，而不是 Claude Code 本体。也就是说：</p><ul><li>Claude Code 仍然要先能正常安装和运行</li><li>Claude Code Hub 负责把地址、Key、模型和环境配置集中起来管理</li></ul><p>Claude Code 本地还没跑通时，先看 <a href="/deploy/claude-code">Claude Code 部署</a>。</p><p>个人单机使用时，通常不需要先上 Claude Code Hub。<br> 一台机器只配自己用时，直接按 <a href="/deploy/claude-code">Claude Code 部署</a> 或用 <a href="/tools/cc-switch">CC-Switch</a> 往往更省事。</p><p>第一次接入时，先把这一点分清楚会省很多时间：</p><ul><li><strong>Claude Code</strong>：真正执行对话、读代码、改文件的 CLI</li><li><strong>Claude Code Hub</strong>：帮你集中管理 Claude Code 相关配置和入口</li></ul><p>也就是说，Hub 解决的是“怎么更统一地管理”，不是“替代 Claude Code 本体”。</p><h2 id="工具介绍" tabindex="-1">工具介绍 <a class="header-anchor" href="#工具介绍" aria-label="Permalink to &quot;工具介绍&quot;">​</a></h2><p>它负责把 Claude Code 相关配置集中起来管理：</p><ul><li>接口地址</li><li>API Key</li><li>模型选择</li><li>常用运行环境</li></ul><p>它更适合解决这类问题：</p><ul><li>多台机器想复用一套 Claude Code 配置</li><li>多个人想统一切换同一批模型和环境</li><li>不想每次换设备都手写同一批环境变量</li></ul><h2 id="适合什么场景" tabindex="-1">适合什么场景 <a class="header-anchor" href="#适合什么场景" aria-label="Permalink to &quot;适合什么场景&quot;">​</a></h2><ul><li>需要多人复用同一套配置模板</li><li>一台机器要切多种模型</li><li>想把 CLI 配置集中管理</li><li>不想每台设备都手动写一遍环境变量</li></ul><p>不太适合的场景：</p><ul><li>只是单机自用，先想把第一条链路跑通</li><li>还没搞清楚 Claude Code 根地址和 <code>/v1</code> 的区别</li><li>还没跑通过一把最小可用的 Claude 专用 Key</li></ul><h2 id="快速部署" tabindex="-1">快速部署 <a class="header-anchor" href="#快速部署" aria-label="Permalink to &quot;快速部署&quot;">​</a></h2><h3 id="部署" tabindex="-1">部署 <a class="header-anchor" href="#部署" aria-label="Permalink to &quot;部署&quot;">​</a></h3><p>按官方项目的安装说明完成部署后，进入管理面板添加自己的配置。</p><h3 id="客户端接入" tabindex="-1">客户端接入 <a class="header-anchor" href="#客户端接入" aria-label="Permalink to &quot;客户端接入&quot;">​</a></h3><p>新建配置时，填写：</p><ul><li>Base URL：<code>https://xiaolan1.cn</code></li><li>API Key：你的 Claude 专用 Key</li><li>模型：从模型广场复制 Claude 系列模型名</li></ul><p>Claude Code / Claude Code Hub 使用 Claude 协议根地址，这里不要加 <code>/v1</code>。Codex 这类直接填写 OpenAI Base URL 的工具才通常填写 <code>https://xiaolan1.cn/v1</code>。Cherry Studio 的服务商地址栏则更适合填写根地址 <code>https://xiaolan1.cn</code>，再由客户端自己补兼容路径。Gemini CLI 当前版本使用官方 Gemini 变量时，也填根地址，再由 CLI 自己拼接 Gemini API 路径。</p><p>第一次接入时，建议先只配一条最小配置：</p><ol><li>一把专门给 Claude Code 用的 Key</li><li>一个已经确认可用的 Claude 系列模型</li><li>一个最简单的测试项目目录</li></ol><p>先确保最小配置能正常返回，再继续拆主力环境、测试环境和多人模板。</p><p>多人环境里使用时，第一次也建议先只接一台机器、一个模型、一个 Key。<br> 这样你能先证明 Hub 到 Claude Code 这一层已经通了，再去扩展第二台设备和更多模板，排障会轻很多。</p><p>真正算接通时，通常要同时满足：</p><ol><li>Claude Code Hub 里保存的配置能正常应用</li><li>Claude Code 启动后没有跳回官方登录流程</li><li><code>/model</code> 或当前会话能读到你刚配置的模型</li><li>发一句短消息后能正常返回</li></ol><p>如果这里只有第 1 步成功，第 2 到第 4 步都不对，优先不要急着改 Hub 结构。<br> 先回头看：</p><ul><li>Claude Code 本机是不是本来就没跑通</li><li>当前 Base URL 是否误填成了 <code>/v1</code></li><li>这把 Key 的分组和模型权限是否真的允许当前模型</li></ul><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to &quot;使用建议&quot;">​</a></h2><ul><li>主力环境和测试环境分开建</li><li>不同设备用不同 Key</li><li>配好后先跑一次最小对话，确认能正常返回</li><li>配置名尽量写清楚设备或用途，后续更好排查</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="和直接配环境变量有什么区别" tabindex="-1">和直接配环境变量有什么区别 <a class="header-anchor" href="#和直接配环境变量有什么区别" aria-label="Permalink to &quot;和直接配环境变量有什么区别&quot;">​</a></h3><p>环境变量更轻，Claude Code Hub 更适合集中管理和切换。</p><p>可以简单理解成：</p><ul><li><strong>环境变量</strong>：适合个人、本机、先跑通</li><li><strong>Claude Code Hub</strong>：适合多设备、多人、集中管理</li></ul><h3 id="为什么模型列表不对" tabindex="-1">为什么模型列表不对 <a class="header-anchor" href="#为什么模型列表不对" aria-label="Permalink to &quot;为什么模型列表不对&quot;">​</a></h3><p>通常是这把 Key 的可见模型范围不同。回控制台或模型广场核对。</p><p>如果保存配置后还是沿用旧模型，先看两件事：</p><ol><li>当前会话是不是已经重新读取了刚保存的配置</li><li>这把 Key 的分组和模型权限里，是不是真的放行了该模型</li></ol><h3 id="保存成功-但-claude-code-还是沿用旧配置" tabindex="-1">保存成功，但 Claude Code 还是沿用旧配置 <a class="header-anchor" href="#保存成功-但-claude-code-还是沿用旧配置" aria-label="Permalink to &quot;保存成功，但 Claude Code 还是沿用旧配置&quot;">​</a></h3><p>先不要急着重建整套 Hub。优先检查：</p><ol><li>当前 Claude Code 会话是不是还没重新读取配置</li><li>本机环境变量里是否还留着旧的 <code>ANTHROPIC_BASE_URL</code> 或 <code>ANTHROPIC_AUTH_TOKEN</code></li><li>当前机器到底接的是 Hub 管理的配置，还是另一套本地手写配置</li></ol><h3 id="为什么-claude-code-hub-里填了-v1-反而不通" tabindex="-1">为什么 Claude Code Hub 里填了 <code>/v1</code> 反而不通 <a class="header-anchor" href="#为什么-claude-code-hub-里填了-v1-反而不通" aria-label="Permalink to &quot;为什么 Claude Code Hub 里填了 `/v1` 反而不通&quot;">​</a></h3><p>因为 Claude Code / Claude Code Hub 走的是 Claude 协议根地址，不是普通 OpenAI 兼容客户端的 <code>/v1</code> 地址。这里应填写：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>https://xiaolan1.cn</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/guide/create-key">创建专属 Key</a></li><li><a href="/deploy/claude-code">Claude Code 部署</a></li><li><a href="/tools/cc-switch">CC-Switch 配置工具</a></li></ul>',52)])])}const p=l(o,[["render",u]]);export{n as __pageData,p as default};
